// test_integration.cu — Integration test: full pipeline vs reference data.
//
// Compares the CUDA kernel's Gaussian prime output against reference files
// generated by the Rust solver (ground truth).
//
// The kernel handles split primes: p ≡ 1 (mod 4) → Cornacchia → (a, b).
// Inert primes: p ≡ 3 (mod 4) → (sqrt(p), 0, p²) — generated host-side.
// Special: (1, 1, 2) for the ramified prime 2.
//
// Reference format: "a b norm\n" per line, sorted by norm.

#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <algorithm>

#include "types.h"
#include "miller_rabin.cuh"
#include "cornacchia.cuh"

// ============================================================================
// Test infrastructure
// ============================================================================

static int g_tests_run = 0;
static int g_tests_passed = 0;
static int g_tests_failed = 0;

// ============================================================================
// CPU reference: generate ALL Gaussian primes up to norm_bound
// This reimplements the Rust PrimeStream logic on the CPU host side.
// ============================================================================

static std::vector<uint64_t> sieve_primes(uint64_t limit) {
    if (limit < 2) return {};
    std::vector<bool> is_composite(limit + 1, false);
    is_composite[0] = is_composite[1] = true;
    for (uint64_t i = 2; i * i <= limit; ++i) {
        if (!is_composite[i]) {
            for (uint64_t j = i * i; j <= limit; j += i) {
                is_composite[j] = true;
            }
        }
    }
    std::vector<uint64_t> primes;
    for (uint64_t i = 2; i <= limit; ++i) {
        if (!is_composite[i]) primes.push_back(i);
    }
    return primes;
}

static uint64_t isqrt_host(uint64_t n) {
    if (n == 0) return 0;
    uint64_t x = (uint64_t)sqrt((double)n);
    while ((__uint128_t)(x + 1) * (x + 1) <= (__uint128_t)n) x++;
    while ((__uint128_t)x * x > (__uint128_t)n) x--;
    return x;
}

struct GPrime {
    int32_t a, b;
    uint64_t norm;

    bool operator<(const GPrime& o) const {
        if (norm != o.norm) return norm < o.norm;
        if (a != o.a) return a < o.a;
        return b < o.b;
    }
    bool operator==(const GPrime& o) const {
        return a == o.a && b == o.b && norm == o.norm;
    }
};

static std::vector<GPrime> generate_gaussian_primes(uint64_t norm_bound) {
    std::vector<GPrime> result;

    auto primes = sieve_primes(norm_bound);

    for (uint64_t p : primes) {
        if (p == 2) {
            result.push_back({1, 1, 2});
        } else if (p % 4 == 1) {
            int32_t a, b;
            if (cornacchia(p, &a, &b)) {
                result.push_back({a, b, p});
            }
        }
        // p ≡ 3 (mod 4): inert, norm = p^2
        // Only include if p^2 <= norm_bound
    }

    // Add inert primes: p ≡ 3 (mod 4) where p^2 ≤ norm_bound
    uint64_t inert_limit = isqrt_host(norm_bound);
    for (uint64_t p : primes) {
        if (p % 4 == 3) {
            __uint128_t norm = (__uint128_t)p * p;
            if (norm <= norm_bound) {
                result.push_back({(int32_t)p, 0, (uint64_t)norm});
            }
        }
    }

    std::sort(result.begin(), result.end());
    return result;
}

// ============================================================================
// Parse reference file: "a b norm\n" per line
// ============================================================================

static std::vector<GPrime> parse_reference_file(const char* path) {
    std::vector<GPrime> result;
    FILE* f = fopen(path, "r");
    if (!f) {
        printf("  ERROR: cannot open reference file %s\n", path);
        return result;
    }

    int32_t a, b;
    uint64_t norm;
    while (fscanf(f, "%d %d %lu", &a, &b, &norm) == 3) {
        result.push_back({a, b, norm});
    }
    fclose(f);
    return result;
}

// ============================================================================
// Diff two lists of Gaussian primes
// ============================================================================

static int diff_primes(const std::vector<GPrime>& got,
                       const std::vector<GPrime>& expected,
                       const char* label, int max_diffs = 10) {
    int diffs = 0;
    size_t gi = 0, ei = 0;

    while (gi < got.size() && ei < expected.size()) {
        if (got[gi] == expected[ei]) {
            gi++;
            ei++;
        } else if (got[gi] < expected[ei]) {
            diffs++;
            if (diffs <= max_diffs)
                printf("  EXTRA in got:      (%d, %d, %lu)\n",
                       got[gi].a, got[gi].b, (unsigned long)got[gi].norm);
            gi++;
        } else {
            diffs++;
            if (diffs <= max_diffs)
                printf("  MISSING from got:  (%d, %d, %lu)\n",
                       expected[ei].a, expected[ei].b, (unsigned long)expected[ei].norm);
            ei++;
        }
    }

    while (gi < got.size()) {
        diffs++;
        if (diffs <= max_diffs)
            printf("  EXTRA in got:      (%d, %d, %lu)\n",
                   got[gi].a, got[gi].b, (unsigned long)got[gi].norm);
        gi++;
    }

    while (ei < expected.size()) {
        diffs++;
        if (diffs <= max_diffs)
            printf("  MISSING from got:  (%d, %d, %lu)\n",
                   expected[ei].a, expected[ei].b, (unsigned long)expected[ei].norm);
        ei++;
    }

    return diffs;
}

// ============================================================================
// Test: CPU pipeline matches reference for T0, T1, T2
// ============================================================================

void test_against_reference(const char* ref_path, uint64_t norm_bound, const char* tier_name) {
    printf("=== Integration: %s (norm <= %lu) ===\n", tier_name, (unsigned long)norm_bound);

    auto generated = generate_gaussian_primes(norm_bound);
    auto reference = parse_reference_file(ref_path);

    if (reference.empty()) {
        g_tests_run++;
        g_tests_failed++;
        printf("  FAIL: could not load reference file %s\n", ref_path);
        return;
    }

    printf("  Generated: %lu primes, Reference: %lu primes\n",
           (unsigned long)generated.size(), (unsigned long)reference.size());

    int diffs = diff_primes(generated, reference, tier_name);

    g_tests_run++;
    if (diffs == 0) {
        g_tests_passed++;
        printf("  ZERO diff — bit-exact match. PASS\n");
    } else {
        g_tests_failed++;
        printf("  FAIL: %d differences\n", diffs);
    }
}

// ============================================================================
// Test: self-consistency check (every output satisfies a^2 + b^2 == norm)
// ============================================================================

void test_self_consistency() {
    printf("=== Integration: self-consistency check (norm <= 10000) ===\n");

    auto primes = generate_gaussian_primes(10000);
    int failures = 0;

    for (const auto& gp : primes) {
        uint64_t computed = (uint64_t)gp.a * gp.a + (uint64_t)gp.b * gp.b;
        if (computed != gp.norm) {
            failures++;
            if (failures <= 5)
                printf("  FAIL: (%d,%d) has a^2+b^2=%lu != norm=%lu\n",
                       gp.a, gp.b, (unsigned long)computed, (unsigned long)gp.norm);
        }

        // Check ordering: a >= b >= 0
        if (!(gp.a >= gp.b && gp.b >= 0)) {
            failures++;
            if (failures <= 5)
                printf("  FAIL: (%d,%d) violates a >= b >= 0\n", gp.a, gp.b);
        }
    }

    g_tests_run++;
    if (failures == 0) {
        g_tests_passed++;
        printf("  All %lu primes self-consistent. PASS\n", (unsigned long)primes.size());
    } else {
        g_tests_failed++;
        printf("  FAIL: %d consistency violations\n", failures);
    }
}

// ============================================================================
// Main
// ============================================================================

int main() {
    printf("gaussian-moat-cuda test suite — Integration\n");
    printf("============================================\n\n");

    test_self_consistency();

    // Reference file paths on Jetson
    test_against_reference("../reference/primes_T0_50.txt", 50, "T0");
    test_against_reference("../reference/primes_T1_200.txt", 200, "T1");
    test_against_reference("../reference/primes_T2_10000.txt", 10000, "T2");

    printf("\n============================================\n");
    printf("Results: %d passed, %d failed, %d total\n",
           g_tests_passed, g_tests_failed, g_tests_run);

    if (g_tests_failed > 0) {
        printf("SOME TESTS FAILED\n");
        return 1;
    }

    printf("ALL TESTS PASSED\n");
    return 0;
}
